mapper.update:

update card
   set order_no=#{orderNo}, deck_title=#{deckTitle}
 where no=#{no}

choose.when:

update card
   set order_no = order_no + 1
 where deck_title = #{deckTitle}
   and order_no >= #{orderNo}

choose.otherwise:

update card
   set order_no = order_no - 1
 where deck_title = #{deckTitle}
   and order_no > #{orderNo}
